patch:
--- a/alu_8bit.v
+++ b/alu_8bit.v
@@ -8,7 +8,7 @@
   input [2:0] op_code;
   output reg [7:0] result;

-  always @(a or b) begin
+  always @(a or b or op_code) begin
     case(op_code)
       3'b000: result = a + b;
       3'b001: result = a - b;

before_code:
module alu_8bit(
  input clk,
  input [7:0] a,
  input [7:0] b,
  input [2:0] op_code,
  output reg [7:0] result
);

  always @(a or b) begin
    case(op_code)
      3'b000: result = a + b;
      3'b001: result = a - b;
      3'b010: result = a & b;
      3'b011: result = a | b;
      default: result = 8'b0;
    endcase
  end

endmodule

after_code:
module alu_8bit(
  input clk,
  input [7:0] a,
  input [7:0] b,
  input [2:0] op_code,
  output reg [7:0] result
);

  always @(a or b or op_code) begin
    case(op_code)
      3'b000: result = a + b;
      3'b001: result = a - b;
      3'b010: result = a & b;
      3'b011: result = a | b;
      default: result = 8'b0;
    endcase
  end

endmodule
